css:
@media print {
  @page {
    size: A4 landscape;
    margin: 8px 10px;
  }
}

.attendance-wrapper {
  padding-right: 0;
}

.attendance-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
  font-size: 8px;
}

.attendance-table th,
.attendance-table td {
  border: 1px solid #000;
  padding-left: 0 !important;
  padding-right: 0 !important;
  padding-top: 1px;
  padding-bottom: 1px;
  text-align: center !important;
  vertical-align: middle !important;
  box-sizing: border-box;
  white-space: nowrap;
  overflow: hidden;
}

.attendance-title {
  font-size: 18px;
  font-weight: bold;
  padding: 8px 0;
  white-space: normal;
}

.attendance-meta {
  font-size: 11px;
  padding: 4px 0;
  text-align: center;
  white-space: normal;
}

.staff-on-duty {
  background-color: #e0e0e0;
  font-weight: bold;
  text-align: center;
}

.attendance-title,
.attendance-meta,
.staff-on-duty,
.attendance-legend {
  vertical-align: middle !important;
}

.signature-row td,
.signature-row th,
.stamp-row td,
.stamp-row th {
  vertical-align: middle !important;
  white-space: normal;
}

.no-attendance {
  background-color: #e0e0e0;
}

.attendance-legend {
  text-align: center;
  font-size: 10px;
  padding: 4px 0;
  white-space: normal;
}

.col-day {
  font-size: 7.5px;
}

.text-left {
  text-align: left !important;
  white-space: normal;
  overflow: hidden;
  overflow-wrap: break-word;
  font-size: 8.5px;
}

html:
{# ======================================================
  BASIC DOC FIELDS
====================================================== #}
{% set project = doc.project %}
{% set site = doc.site %}
{% set month = doc.month %}
{% set year = doc.year | int %}
{% set is_shift_hours = (doc.attendance_based_on == "Shift Hours") %}
{# ======================================================
  ATTENDANCE DATA
====================================================== #}
{% set attendance = doc.attendance_details or [] %}
{% set overtime = doc.overtime_details or [] %}
{% set data = attendance + overtime %}
{# ======================================================
  STATUS MAP (for non-shift-hours mode)
====================================================== #}
{% set status_map = {
  "Present": "P",
  "Absent": "A",
  "On Leave": "OL",
  "Holiday": "H",
  "Day Off": "DO",
  "Client Day Off": "DO",
  "On Hold": "OH"
} %}
{# ======================================================
  DAYS IN MONTH (JINJA-ONLY CALCULATION)
====================================================== #}
{% set month_index = {
  "January": 1, "February": 2, "March": 3, "April": 4,
  "May": 5, "June": 6, "July": 7, "August": 8,
  "September": 9, "October": 10, "November": 11, "December": 12
}[month] %}
{% set month_days = {
  1: 31, 2: 28, 3: 31, 4: 30, 5: 31, 6: 30,
  7: 31, 8: 31, 9: 30, 10: 31, 11: 30, 12: 31
} %}
{% set days_in_month = month_days[month_index] %}
{# Leap year adjustment for February #}
{% if month_index == 2 and ((year % 4 == 0 and year % 100 != 0) or (year % 400 == 0)) %}
    {% set days_in_month = 29 %}
{% endif %}
{% set days = range(1, days_in_month + 1) %}
{# ======================================================
  TOTAL COLUMNS
====================================================== #}
{# 1 SNo + 4 Employee ID + 5 Employee Name + 2 Shift + days_in_month + 2 Working + 2 Off #}
{% set total_columns = 1 + 4 + 5 + 2 + days_in_month + 2 + 2 %}
{# ======================================================
  META ROW COLSPANS
====================================================== #}
{% set header_colspan = 3 %}
{% set remaining_cols = total_columns - (header_colspan * 3) %}
{% set project_data_colspan = remaining_cols * 40 // 100 %}
{% set site_data_colspan = remaining_cols * 40 // 100 %}
{% set month_data_colspan = remaining_cols - project_data_colspan - site_data_colspan %}

<div class="attendance-wrapper">
<table class="attendance-table">

<!-- ================= COLGROUP ================= -->
<colgroup>
  <!-- # -->
  <col style="width:22px">
  <!-- Employee ID (4 cols) -->
  <col style="width:25px"><col style="width:25px"><col style="width:25px"><col style="width:25px">
  <!-- Employee Name (5 cols) -->
  <col style="width:26px"><col style="width:26px"><col style="width:26px"><col style="width:26px"><col style="width:26px">
  <!-- Shift (2 cols) -->
  <col style="width:34px"><col style="width:34px">
  <!-- Day columns -->
  {% for d in days %}
  <col style="width:20px">
  {% endfor %}
  <!-- Working Days (2 cols) -->
  <col style="width:26px"><col style="width:26px">
  <!-- Days Off (2 cols) -->
  <col style="width:26px"><col style="width:26px">
</colgroup>

<!-- ================= TITLE ================= -->
<tr style="height: 60px;">
  <th colspan="{{ total_columns }}" class="attendance-title">
    Monthly Attendance Sheet
  </th>
</tr>
<!-- ================= META ================= -->
<tr class="attendance-meta">
  <td colspan="{{ header_colspan }}"><strong>Project</strong></td>
  <td colspan="{{ project_data_colspan }}">{{ project }}</td>
  <td colspan="{{ header_colspan }}"><strong>Site</strong></td>
  <td colspan="{{ site_data_colspan }}">{{ site }}</td>
  <td colspan="{{ header_colspan }}"><strong>Month</strong></td>
  <td colspan="{{ month_data_colspan }}">{{ month }} {{ year }}</td>
</tr>
<!-- ================= HEADER (2 ROWS) ================= -->
<tr>
  <th class="col-sno" rowspan="2">#</th>
  <th class="col-empid" rowspan="2" colspan="4">Employee ID</th>
  <th class="col-name" rowspan="2" colspan="5">Employee Name</th>
  <th rowspan="2" colspan="2">Shift</th>
  {% for d in days %}
    <th class="col-day">{{ d }}</th>
  {% endfor %}
  <th class="col-total" rowspan="2" colspan="2">Working Days</th>
  <th class="col-total" rowspan="2" colspan="2">Days Off</th>
</tr>
<tr>
  {% for d in days %}
    {# Build a proper date and get weekday using frappe.utils #}
    {% set date_obj = frappe.utils.getdate([year, month_index, d]|join("-")) %}
    <th class="col-day">
      {{ frappe.utils.formatdate(date_obj, "EEE") }}
    </th>
  {% endfor %}
</tr>
<!-- ================= ROWS ================= -->
{% for row in data %}
<tr>
  <td>{{ loop.index }}</td>
  <td class="text-left" colspan="4">{{ row.employee_id or "" }}</td>
  <td class="text-left" colspan="5">{{ row.employee_name or "" }}</td>
  <td class="text-left" colspan="2">{{ row.shift or "" }}</td>
  {# init working day counter for shift-hours mode #}
  {% set ns = namespace(working_days=0) %}
  {% for d in days %}
    {% if is_shift_hours %}
      {# Shift Hours mode: use day_X_hour and render hours with 1 decimal #}
      {% set field = "day_" ~ d ~ "_hour" %}
      {% set value = row.get(field) %}
      {% set hours = frappe.utils.flt(value) %}
      {% if hours > 8 %}
        {% set ns.working_days = ns.working_days + 1 %}
      {% endif %}
      {% set display = frappe.utils.flt(value, 1) if value else "" %}
    {% else %}
      {# Status mode: use day_X and render status code #}
      {% set field = "day_" ~ d %}
      {% set value = row.get(field) or "" %}
      {% set display = status_map[value] if value in status_map else "" %}
    {% endif %}
    <td class="{{ 'no-attendance' if not value else '' }}">
      {{ display }}
    </td>
  {% endfor %}
  {# Working Days column: use computed value for shift-hours, existing field otherwise #}
  <td colspan="2">
    {% if is_shift_hours %}
      {{ ns.working_days }}
    {% else %}
      {{ row.working_days or 0 }}
    {% endif %}
  </td>
  <td colspan="2">{{ row.off_days or 0 }}</td>
</tr>
{% endfor %}
{# ================= STAFF ON DUTY (ONLY FOR NON-SHIFT-HOURS) ================= #}
{% if not is_shift_hours %}
<tr class="staff-on-duty">
  {# 1 + 4 + 5 + 2 = 12 fixed columns before days #}
  <td colspan="12"><strong>Staff on Duty</strong></td>
  {% for d in days %}
      {% set ns = namespace(count=0) %}
      {% for row in data %}
          {% set field = "day_" ~ d %}
          {% set value = row.get(field, "") %}
          {% if value == "Present" %}
              {% set ns.count = ns.count + 1 %}
          {% endif %}
      {% endfor %}
      <td>{{ ns.count }}</td>
  {% endfor %}
  <td colspan="2"></td>
  <td colspan="2"></td>
</tr>
{% endif %}
{# ================= SIGNATURE / STAMP ROWS ================= #}
{% set col_1 = total_columns // 4 %}
{% set col_2 = total_columns // 4 %}
{% set col_3 = total_columns // 4 %}
{% set col_4 = total_columns - col_1 - col_2 - col_3 %}
<tr class="signature-row" style="height: 40px;">
  <td colspan="{{ col_1 }}"><strong>Supervisor Name &amp; Signature:</strong></td>
  <td colspan="{{ col_2 }}"></td>
  <td colspan="{{ col_3 }}"><strong>Client Name &amp; Signature:</strong></td>
  <td colspan="{{ col_4 }}"></td>
</tr>
<tr class="stamp-row" style="height: 60px;">
  <td colspan="{{ col_1 }}">Stamp</td>
  <td colspan="{{ col_2 }}"></td>
  <td colspan="{{ col_3 }}">Stamp</td>
  <td colspan="{{ col_4 }}"></td>
</tr>
{# ================= LEGEND ================= #}
{% if not is_shift_hours %}
<tr>
  <td colspan="{{ total_columns }}" class="attendance-legend">
    {% for label, code in status_map.items() %}
      {{ code }} = {{ label }}{% if not loop.last %} &nbsp;|&nbsp; {% endif %}
    {% endfor %}
  </td>
</tr>
{% endif %}
</table>
</div>
